{
  "name": "テスト花子02",
  "talent": {
    "axis1": {
      "name": "傾聴力",
      "english": "Deep Listening",
      "description": "子どもの声に耳を傾け、変化を見逃さない感受性",
      "items": ["子どもの話を聞く", "変化に気づく", "記録をつける"],
      "percentage": 35,
      "top5": ["子どもの話を聞く", "変化に気づく"]
    },
    "axis2": {
      "name": "育成力",
      "english": "Nurturing",
      "description": "根気強く教え、励まし、成長を引き出す粘り強さ",
      "items": ["根気強く教える", "励ます", "褒める", "巻き込む"],
      "percentage": 40,
      "top5": ["励ます", "根気強く教える"]
    },
    "axis3": {
      "name": "場づくり",
      "english": "Space Making",
      "description": "その場にいるだけで空気が温かくなる雰囲気づくり",
      "items": ["場を和ませる", "絵を描く"],
      "percentage": 25,
      "top5": ["場を和ませる"]
    }
  },
  "value": {
    "axis1": {
      "name": "誠実さ",
      "english": "Integrity",
      "description": "一人ひとりと正直に向き合い、手を抜かない姿勢",
      "items": ["誠実", "正直", "素直さ"],
      "percentage": 40,
      "top5": ["誠実"]
    },
    "axis2": {
      "name": "成長志向",
      "english": "Growth",
      "description": "自他ともに伸び続けることへの深い信頼",
      "items": ["成長", "粘り強さ", "努力"],
      "percentage": 35,
      "top5": ["成長", "粘り強さ"]
    },
    "axis3": {
      "name": "公正と愛",
      "english": "Fairness & Care",
      "description": "誰一人取りこぼさない平等な眼差しと思いやり",
      "items": ["公平", "思いやり", "協調"],
      "percentage": 25,
      "top5": ["公平", "思いやり"]
    }
  },
  "passion": {
    "axis1": {
      "name": "教育実践",
      "english": "Education",
      "description": "教室という場で子どもと共に何かを育てていく喜び",
      "items": ["教育", "学級づくり", "読み聞かせ"],
      "percentage": 45,
      "top5": ["教育", "読み聞かせ", "学級づくり"]
    },
    "axis2": {
      "name": "子どもの成長",
      "english": "Child Growth",
      "description": "一人の子が変わる瞬間に立ち会いたいという衝動",
      "items": ["子どもの成長"],
      "percentage": 35,
      "top5": ["子どもの成長"]
    },
    "axis3": {
      "name": "表現と感性",
      "english": "Expression",
      "description": "声・絵・言葉で何かを伝え合う場への愛着",
      "items": ["合唱", "絵本", "ガーデニング", "旅行"],
      "percentage": 20,
      "top5": ["合唱"]
    }
  },
  "core_words": {
    "talent_core": "根気強く教える",
    "value_core": "誠実",
    "passion_core": "子どもの成長"
  },
  "kakuchiiki": "誠実に子どもの声を聴きながら成長の場を育てる人",
  "kakuchiiki_options": [
    "一人ひとりに誠実に向き合い、学級という場で子どもの成長を根気強く支える人",
    "子どもの変化を見逃さず、読み聞かせや合唱を通じて成長の喜びを届ける人",
    "しんどさを抱えた子どもの隣に座り、誠実に話を聴いて学びへの意欲を引き出す人"
  ],
  "insight": "「あなたは大切」と伝えきれたか——その問いを心に抱えたまま教壇に立ち続けてきた。それはあなたが誰よりも、子ども一人ひとりの存在を全身で受け取ってきた証拠だ。根気強く教え、場を和ませ、変化に気づく。その才能は教室の中だけでなく、しんどさを抱えた子や先生が全国にいる今の時代に、静かに、しかし確実に必要とされている。10年後、教え子が誰かの隣に座って支えている。その連鎖の起点は、あなたが諦めずに声を聴き続けたあの瞬間たちだ。あなたにしか開けない扉がある——それは「誰かの隣にいる」ことを仕事にできる世界への扉だ。",
  "what": {
    "products": [
      "学級担任として日々の読み聞かせや合唱活動を通じて、子どもが「自分は大切にされている」と感じる学級づくりを実践する",
      "教員仲間や保護者向けに「子どもの変化の見つけ方・声の聴き方」をテーマにした小さな勉強会を開く",
      "しんどさを抱えた子どもや先生のための傾聴・対話型の放課後サポートの場を学校内外に立ち上げる",
      "自身の教育実践をnoteや冊子にまとめ、「誠実な学級づくり」の記録を全国の教員へ届ける",
      "全国の学校を訪ね歩き、子どもと先生の声を聴いて回るフィールドワーク型の教育支援活動を展開する"
    ],
    "actions": "今日受け持った子の中で「最近変化があったかも」と感じる一人の名前を手帳に書き、明日その子の隣に少し長く座ってみる。",
    "offer": "一人の子どもが「自分は大切にされている」と感じた瞬間、その子の人生の地図に温かい道が一本増える。あなたが誠実に隣にいることで、その連鎖が静かに、しかし確かに広がっていく。"
  },
  "reward": {
    "economic": "教育実践の講座・保護者向けワークショップ・教員研修の講師として収益が生まれ、実践をまとめた絵本や冊子が教育現場で読まれ続ける。",
    "social": "10年後、かつての教え子が「先生がいたから、私も誰かの話を聴こうと思えた」と笑顔で話しているその場面に、あなたがいる。",
    "intrinsic": "気づいたら子どもの話に耳を傾けている。根気強く教え続けることに迷いがない。それがあなたの呼吸だから。",
    "model": "誠実に子どもの声を聴き続けることが、講座・出版・研修という形で世界に届き、支えた子どもたちが次の誰かを支える連鎖を生みながら、あなた自身も経済的・精神的に豊かであり続けるモデル。"
  }
}
